	var item={title:title,url:url};
	item.style={layout_flexGrow:type1,layout_flexBasisPercent:type2};
	sort.push(item)
};
const categories=[
	["入库","category.html","orderBy=public"],
	["点击","category.html","orderBy=click"],
	["更新","category.html","orderBy=update"],
	["推荐","category.html"],
	["🌀标签🌀","","",1,1],
	["单篇","category.php","catId=danpian"],
	["古典","category.php","catId=gudian"],
	["历史","category.php","catId=lishi"],
	["都市","category.php","catId=dushi"],
	["乡土","category.php","catId=xiangtu"],
	["官场","category.php","catId=guanchang"],
	["校园","category.php","catId=xiaoyuan"],
	["武侠","category.php","catId=wuxia"],
	["同人","category.php","catId=tongren"],
	["穿越","category.php","catId=chuanyue"],
	["🍥新书榜🍥","ranking.php","t=newbook",1,1]
];
categories.forEach(item=>{
	const [title,path,params,type1,type2]=item;
	let url="/"+path;
	const hasParams=Boolean(params);
	if (params){
		url+="?"+params
	}
	if (title!=="新书"){
		url+=(hasParams?"&":"?")+"pageNum={{page}}";
	}
	if (item.length>=5){
		push(title,url,type1,type2)
	}else{
		push(title,url)
	}
});
